interface MoneyWorksFieldMetadata {
  fieldName: string;
  dataType: MoneyWorksDataType;
  maxLength?: number;
  canonicalDescription: string;
  manualSource: string;
  isRequired?: boolean;
  isIndexed?: boolean;
}

items.example:
const taxCodeMeta: MoneyWorksFieldMetadata = {
  fieldName: 'TaxCode',
  dataType: MoneyWorksDataType.TEXT,
  maxLength: 5,
  canonicalDescription: 'The tax code',
  manualSource: 'Appendix B - Tax Rates',
  isRequired: true,
  isIndexed: true
};

