import { TaxRates } from '@moneyworks/canonical';
import { YYYYMMDD, AccountCode } from '@moneyworks/utilities';

const taxRate: TaxRates.MoneyWorksTaxRate = {
  TaxCode: 'GST10',
  PaidAccount: '2100' as AccountCode,
  RecAccount: '2110' as AccountCode,
  Date: '20240101' as YYYYMMDD,
  Rate1: 10,
  Rate2: 10
};

const validation = TaxRates.validateTaxRate(taxRate);
if (!validation.isValid) {
  console.error('Tax rate validation failed:', validation.warnings);
}

import { TaxRates } from '@moneyworks/canonical';
import { YYYYMMDD } from '@moneyworks/utilities';

// Tax rate changes from 10% to 15% on July 1, 2024
const taxRate: TaxRates.MoneyWorksTaxRate = {
  TaxCode: 'GST',
  PaidAccount: '2100' as AccountCode,
  RecAccount: '2110' as AccountCode,
  Date: '20240701' as YYYYMMDD,
  Rate1: 10,  // Before July 1
  Rate2: 15   // On or after July 1
};

// Transaction on June 15 - uses Rate1 (10%)
const juneResult = TaxRates.calculateTaxForRate(
  taxRate,
  1000,
  { transactionDate: '20240615' as YYYYMMDD, isInclusive: false }
);
console.log(juneResult.taxAmount); // 100

// Transaction on July 15 - uses Rate2 (15%)
const julyResult = TaxRates.calculateTaxForRate(
  taxRate,
  1000,
  { transactionDate: '20240715' as YYYYMMDD, isInclusive: false }
);
console.log(julyResult.taxAmount); // 150

import { TaxRates } from '@moneyworks/canonical';

// GST (federal tax)
const gst: TaxRates.MoneyWorksTaxRate = {
  TaxCode: 'GST5',
  PaidAccount: '2100' as AccountCode,
  RecAccount: '2110' as AccountCode,
  Date: '20240101' as YYYYMMDD,
  Rate1: 5,
  Rate2: 5
};

// PST (provincial tax) - compounds on GST
const pst: TaxRates.MoneyWorksTaxRate = {
  TaxCode: 'PST7',
  PaidAccount: '2120' as AccountCode,
  RecAccount: '2130' as AccountCode,
  Date: '20240101' as YYYYMMDD,
  Rate1: 7,
  Rate2: 7,
  Combine: TaxRates.MoneyWorksTaxCombineMode.ADD_AFTER
};

const result = TaxRates.calculateCombinedTax(
  gst,
  pst,
  1000,
  { transactionDate: '20240615' as YYYYMMDD, isInclusive: false }
);

console.log(result.tier1Tax);   // 50.00 (5% GST)
console.log(result.tier2Tax);   // 73.50 (7% PST on $1050)
console.log(result.totalTax);   // 123.50
console.log(result.grossAmount); // 1123.50

import { TaxRates, MoneyWorksDataType } from '@moneyworks/canonical';

// Get metadata for a specific field
const taxCodeMeta = TaxRates.getFieldMetadata('TaxCode');
console.log(taxCodeMeta);
// {
//   fieldName: 'TaxCode',
//   dataType: MoneyWorksDataType.TEXT,
//   maxLength: 5,
//   canonicalDescription: 'The tax code',
//   manualSource: 'Appendix B, Page 567',
//   isRequired: true,
//   isIndexed: true
// }

// Get all required fields
const requiredFields = TaxRates.getRequiredFields();
console.log(requiredFields);
// ['TaxCode', 'PaidAccount', 'RecAccount', 'Date', 'Rate1', 'Rate2']

// Check field types
const allFields = TaxRates.MONEYWORKS_TAX_RATE_FIELDS;
Object.entries(allFields).forEach(([field, meta]) => {
  if (meta.dataType === MoneyWorksDataType.NUMERIC) {
    console.log(`${field} is a numeric field`);
  }
});
